import{_ as a}from"./chunks/pricing.xnwHCEuz.js";import{_ as l,o,c as i,a2 as s}from"./chunks/framework.BflysNKA.js";const m=JSON.parse('{"title":"Codex","description":"","frontmatter":{},"headers":[],"relativePath":"tools/codex.md","filePath":"tools/codex.md","lastUpdated":1778577020000}'),n={name:"tools/codex.md"};function d(t,e,p,c,r,h){return o(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="codex" tabindex="-1">Codex <a class="header-anchor" href="#codex" aria-label="Permalink to &quot;Codex&quot;">​</a></h1><p>Codex 适合已经熟悉 OpenAI CLI 工作流，或者希望用配置文件稳定管理模型、网关和默认行为的用户。</p><p>如果你要把 Codex 接到 小蓝中转站，优先看：<a href="/deploy/codex">Codex 部署</a>。</p><h2 id="codex-为什么和别的-cli-不太一样" tabindex="-1">Codex 为什么和别的 CLI 不太一样 <a class="header-anchor" href="#codex-为什么和别的-cli-不太一样" aria-label="Permalink to &quot;Codex 为什么和别的 CLI 不太一样&quot;">​</a></h2><p>Codex 不是那种“临时导出两个变量就结束”的工具。<br> 它更适合把长期默认值写进 <code>~/.codex/config.toml</code>，再用环境变量单独提供 Key。</p><p>这样做的好处是：</p><ul><li>默认模型、审批策略、沙箱模式都能固定下来</li><li>换项目时不用每次重新输入</li><li>Key 轮换时只改环境变量，不用动主配置</li></ul><p>第一次接入时，先记住这三项最关键：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>config.toml 里的 base_url: https://xiaolan1.cn/v1</span></span>
<span class="line"><span>config.toml 里的 wire_api: responses</span></span>
<span class="line"><span>环境变量里的 小蓝中转站_API_KEY: sk-你的专属Key</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>和 Claude Code 不同，Codex 这里的地址要带 <code>/v1</code>。<br> 如果把根地址直接写进 <code>base_url</code>，看起来像是“命令能启动但对话不正常”，很多人会误判成 Key 或模型问题。</p><h2 id="第一次接入前先准备" tabindex="-1">第一次接入前先准备 <a class="header-anchor" href="#第一次接入前先准备" aria-label="Permalink to &quot;第一次接入前先准备&quot;">​</a></h2><ul><li>一把给 Codex 单独使用的 Key，例如 <code>Mac-Codex</code>（侧边栏 <strong>API 密钥</strong> 创建）</li><li>一个先拿来测试的轻量模型名（从模型广场复制）</li><li><code>node</code>、<code>npm</code>、<code>git</code> 都能正常使用</li><li>确认自己准备走 npm、Homebrew 还是 Release 安装</li></ul><p><img src="`+a+`" alt="模型广场 — 复制模型名作为 config.toml 里的 model 字段"></p><p>Key 单独拆出来的意义，不只是“看起来整齐”，而是后面查日志、做额度上限、停用某台机器时会非常省事。</p><h2 id="codex-最常见的三处填写" tabindex="-1">Codex 最常见的三处填写 <a class="header-anchor" href="#codex-最常见的三处填写" aria-label="Permalink to &quot;Codex 最常见的三处填写&quot;">​</a></h2><p>第一次配置时，先把下面三项记住：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>config.toml 里的 base_url: https://xiaolan1.cn/v1</span></span>
<span class="line"><span>config.toml 里的 wire_api: responses</span></span>
<span class="line"><span>环境变量里的 小蓝中转站_API_KEY: sk-你的专属Key</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>为什么这么拆：</p><ul><li><code>base_url</code> 决定 Codex 请求发到哪里</li><li><code>wire_api</code> 决定它和 小蓝中转站 说哪一种协议</li><li><code>小蓝中转站_API_KEY</code> 决定这次请求用哪一把凭证</li></ul><p>少掉任何一层，看起来都可能像“Codex 连不上”。</p><p>如果你还没完全确定先用哪个模型，最稳的顺序通常是：</p><ol><li>Key 分组先用 <code>auto</code> 或默认分组</li><li><code>model</code> 先写一个轻量模型</li><li>跑通第一次对话后，再换成代码能力更强的模型</li></ol><h2 id="为什么模型名一定要从模型广场复制" tabindex="-1">为什么模型名一定要从模型广场复制 <a class="header-anchor" href="#为什么模型名一定要从模型广场复制" aria-label="Permalink to &quot;为什么模型名一定要从模型广场复制&quot;">​</a></h2><p>Codex 能不能启动，不代表模型名一定写对。<br> 很多“明明配置都没问题”的报错，最后都卡在模型名用了旧教程里的历史值。</p><p>最稳的方式始终是：</p><ol><li>打开<a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">模型广场</a></li><li>复制完整模型名</li><li>写进 <code>config.toml</code> 的 <code>model</code></li><li>第一次先用轻量模型确认链路</li></ol><h2 id="第一次成功的判断" tabindex="-1">第一次成功的判断 <a class="header-anchor" href="#第一次成功的判断" aria-label="Permalink to &quot;第一次成功的判断&quot;">​</a></h2><p>第一次接入成功，不只是看到 <code>codex</code> 命令能打开，而是要同时满足：</p><ol><li>命令能正常启动</li><li>不会把你带回官方登录流程</li><li>发一条短消息后能正常返回回复</li><li>当前用的模型确实是你刚写进去的那个</li></ol><p>这一步走通后，再切到真实项目目录会清楚很多。</p><h2 id="继续配置" tabindex="-1">继续配置 <a class="header-anchor" href="#继续配置" aria-label="Permalink to &quot;继续配置&quot;">​</a></h2><ul><li>详细安装与配置： <a href="/deploy/codex">Codex 部署</a></li><li>先准备命令行环境： <a href="/beginner/windows">Windows 快速接入</a> / <a href="/beginner/macos">macOS 快速接入</a></li><li>先准备账号、分组和 Key： <a href="/guide/registration">注册账号</a></li><li>不想手写配置： <a href="/tools/cc-switch">CC-Switch</a></li></ul>`,32)])])}const x=l(n,[["render",d]]);export{m as __pageData,x as default};
